def mse_reconstruction_loss(x_recon, x_target):
    """
    MSE reconstruction loss — Gaussian decoder with unit variance.
    x_recon:  decoder output, shape (B, D)
    x_target: continuous target, shape (B, D)
    Returns: scalar (mean over batch and dims)
    """
    return F.mse_loss(x_recon, x_target, reduction='mean')

# Note: with fixed σ²=1, MSE is proportional to -log N(x; recon, I).
# If σ² is learned or set differently, scale the MSE accordingly:
def gaussian_nll(x_recon, x_target, log_var=0.0):
    """Exact Gaussian NLL with per-element log variance."""
    return 0.5 * (log_var + (x_target - x_recon).pow(2) / log_var.exp()).mean()

import torch
import torch.nn as nn
import torch.nn.functional as F


# Step 1: Build encoder that outputs mu and log_var
class Encoder(nn.Module):
    def __init__(self, input_dim=784, hidden=256, latent_dim=16):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(input_dim, hidden), nn.ReLU(),
            nn.Linear(hidden, hidden), nn.ReLU(),
        )
        self.mu_head     = nn.Linear(hidden, latent_dim)
        self.logvar_head = nn.Linear(hidden, latent_dim)

    def forward(self, x):
        h = self.net(x)
        return self.mu_head(h), self.logvar_head(h)


# Step 2: Build decoder — output depends on the chosen loss
class Decoder(nn.Module):
    def __init__(self, latent_dim=16, hidden=256, output_dim=784):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(latent_dim, hidden), nn.ReLU(),
            nn.Linear(hidden, hidden), nn.ReLU(),
            nn.Linear(hidden, output_dim),
            # No sigmoid here — BCE with logits needs raw logits
        )

    def forward(self, z):
        return self.net(z)  # raw logits


class VAE(nn.Module):
    def __init__(self, loss_type='bce'):
        super().__init__()
        self.encoder = Encoder()
        self.decoder = Decoder()
        assert loss_type in ('bce', 'mse')
        self.loss_type = loss_type

    # Step 3: Reparameterisation trick — differentiable sampling
    def reparameterise(self, mu, log_var):
        std = torch.exp(0.5 * log_var)
        return mu + std * torch.randn_like(std)

    def forward(self, x):
        mu, log_var = self.encoder(x)
        z = self.reparameterise(mu, log_var)
        return self.decoder(z), mu, log_var

    # Step 4: Compute ELBO loss with configurable reconstruction term
    def elbo_loss(self, x, x_logits, mu, log_var, beta=1.0):
        if self.loss_type == 'bce':
            # Sum over pixels (D), mean over batch (B)
            recon = F.binary_cross_entropy_with_logits(
                x_logits, x, reduction='sum') / x.size(0)
        else:
            recon = F.mse_loss(torch.sigmoid(x_logits), x, reduction='mean')

        # KL divergence: -0.5 * sum(1 + log_var - mu^2 - exp(log_var))
        kl = -0.5 * (1 + log_var - mu.pow(2) - log_var.exp()).sum(1).mean()
        return recon + beta * kl, recon.item(), kl.item()


# Step 5: Training loop with KL annealing
def train_vae(vae, dataloader, epochs=50, warmup=20):
    opt = torch.optim.Adam(vae.parameters(), lr=1e-3)
    for epoch in range(epochs):
        beta = min(1.0, (epoch + 1) / warmup)  # linear KL ramp
        for x, _ in dataloader:
            x = x.view(x.size(0), -1)           # flatten to (B, 784)
            opt.zero_grad()
            x_logits, mu, log_var = vae(x)
            loss, recon, kl = vae.elbo_loss(x, x_logits, mu, log_var, beta)
            loss.backward()
            opt.step()
        if epoch % 10 == 0:
            print(f'epoch {epoch}: recon={recon:.2f} kl={kl:.2f} beta={beta:.2f}')
